class Solution {
public:
int calculate_stack_sum(vector<int>& nums) {
  int sum = 0;
  stack<int> s;
  for (int& num : nums) {
    if (num % 2 == 0) {
      s.push(num);
    } else {
      if (!s.empty()) {
        sum += s.top();
        s.pop();
      }
    }
  }
  return sum;
}

int main() {
  Solution solution;
  int n;
  cin >> n;
  vector<int> nums(n);
  for (int& num : nums) {
    cin >> num;
  }
  int sum = solution.calculate_stack_sum(nums);
  if (sum == 0) {
    cout << -1 << endl;
  } else {
    cout << sum << endl;
  }
  return 0;
}
